class FixedWindowLimiter:
    def __init__(self, limit, window_seconds):
        self.limit = limit
        self.window_seconds = window_seconds
        self.windows = {}

    def allow(self, key, timestamp):
        window_start, count = self.windows.get(key, (None, 0))
        if window_start is None or timestamp >= window_start + self.window_seconds:
            window_start = timestamp - (timestamp % self.window_seconds)
            count = 0
        count += 1
        self.windows[key] = (window_start, count)
        return count <= self.limit
